// E03S03 — AC2, AC3, AC4: Build canonical tech notification SMS body
// Assembles message using only data from upstream nodes — never hardcoded values

const businessName = $('GET Client Details').item.json.business_name;
const customerName = $('GET Job Details').item.json.customer_name;
const serviceAddress = $('GET Job Details').item.json.service_address;
const customerPhone = $('GET Job Details').item.json.customer_phone;
const issueDescription = $('GET Job Details').item.json.issue_description;
const token = $('Trigger: Tech SMS Webhook').item.json.body.token;
const techPhone = $('GET Tech Details').item.json.phone;
const contactMethod = $('GET Tech Details').item.json.contact_method;
const techName = $('GET Tech Details').item.json.name;

// Validate required fields — fail loudly, not silently
if (!businessName) throw new Error('[E03S03] Missing clients.business_name — cannot build SMS');
if (!customerName) throw new Error('[E03S03] Missing jobs.customer_name — cannot build SMS');
if (!serviceAddress) throw new Error('[E03S03] Missing jobs.service_address — cannot build SMS');
if (!customerPhone) throw new Error('[E03S03] Missing jobs.customer_phone — cannot build SMS');
if (!issueDescription) throw new Error('[E03S03] Missing jobs.issue_description — cannot build SMS');
if (!token) throw new Error('[E03S03] Missing token from webhook payload — cannot build magic link');
if (!techPhone) throw new Error('[E03S03] Missing techs.phone — cannot send SMS');

// AC3: Magic link URL format — https://tech.sendjob.app?token=[token]
const magicLinkUrl = 'https://tech.sendjob.app?token=' + token;

// AC4: Canonical SMS template from conventions.md
// [Business Name] - New job assigned: [Customer], [Address], [Phone]. Issue: [Description]. View job: [URL]
const baseMessage = businessName + ' - New job assigned: ' + customerName + ', ' + serviceAddress + ', ' + customerPhone + '. Issue: ' + issueDescription + '. View job: ' + magicLinkUrl;

// Opt-out language: append on every SMS to remain compliant (conservative approach)
// Story notes: 'include opt-out on first SMS to a new contact'
// Safe default: always include — Twilio A2P 10DLC compliance requires it on first contact
const smsBody = baseMessage + ' Reply STOP to unsubscribe.';

return [{
  json: {
    smsBody: smsBody,
    techPhone: techPhone,
    contactMethod: contactMethod,
    businessName: businessName,
    techName: techName,
    magicLinkUrl: magicLinkUrl
  }
}];

// E03S03 — AC6: Email path stub
// The email notification path is acceptable as a stub for Sprint 3.
// SMS is the primary delivery path. Email will be implemented in a future sprint.

const techName = $('Build SMS Body').item.json.techName;
const businessName = $('Build SMS Body').item.json.businessName;
const magicLinkUrl = $('Build SMS Body').item.json.magicLinkUrl;
const contactMethod = $('GET Tech Details').item.json.contact_method;

console.log('[SendJob] E03S03: email contact_method detected for tech=' + techName + ' — email path not yet implemented (Sprint 3 stub)');
console.log('[SendJob] E03S03: business=' + businessName + ' magicLink=' + magicLinkUrl);

// Return stub result — workflow continues to respond to webhook
return [{
  json: {
    stub: true,
    contactMethod: contactMethod,
    techName: techName,
    note: 'Email path: stub — not yet implemented. Tech notification not sent. Implement in future sprint.'
  }
}];
